class Solution:
    def numJewelsInStones(self, jewels, stones):
        count = 0
        for s in stones:
            for j in jewels:
                if s == j:
                    count += 1
                    break
        return count

solutions.python:
class Solution:
    def numJewelsInStones(self, jewels, stones):
        jset = set(jewels)
        return sum(1 for s in stones if s in jset)

